import React, { useState, useEffect } from 'react';
import { Clock, Plus, Trash2, Edit2, AlertCircle } from 'lucide-react';
import { AvailabilitySlot } from '../../types';
import { Button } from '../ui/Button';
import { Input } from '../ui/Input';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Badge } from '../ui/Badge';
import {
  createAvailabilitySlot,
  updateAvailabilitySlot,
  deleteAvailabilitySlot,
  hasOverlappingSlot,
  isValidTimeRange,
  validateTimeFormat,
  getAvailabilitySlotsForUser
} from '../../data/availabilitySlots';

interface AvailabilitySlotFormProps {
  userId: string;
  onSlotAdded?: (slot: AvailabilitySlot) => void;
  onSlotUpdated?: (slot: AvailabilitySlot) => void;
  onSlotDeleted?: (slotId: string) => void;
}

const DAYS_OF_WEEK = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

export const AvailabilitySlotForm: React.FC<AvailabilitySlotFormProps> = ({
  userId,
  onSlotAdded,
  onSlotUpdated,
  onSlotDeleted
}) => {
  const [slots, setSlots] = useState<AvailabilitySlot[]>([]);
  const [selectedDay, setSelectedDay] = useState<string>('Monday');
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('10:00');
  const [error, setError] = useState<string | null>(null);
  const [editingSlotId, setEditingSlotId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    // Load existing slots
    const userSlots = getAvailabilitySlotsForUser(userId);
    setSlots(userSlots);
  }, [userId]);

  const handleAddSlot = () => {
    setError(null);
    setIsLoading(true);

    try {
      // Validation
      if (!validateTimeFormat(startTime)) {
        setError('Invalid start time format');
        return;
      }

      if (!validateTimeFormat(endTime)) {
        setError('Invalid end time format');
        return;
      }

      if (!isValidTimeRange(startTime, endTime)) {
        setError('Start time must be before end time');
        return;
      }

      if (hasOverlappingSlot(userId, selectedDay, startTime, endTime)) {
        setError('This time slot overlaps with an existing slot');
        return;
      }

      const newSlot = createAvailabilitySlot(userId, selectedDay, startTime, endTime);

      if (newSlot) {
        setSlots([...slots, newSlot]);
        setStartTime('09:00');
        setEndTime('10:00');
        if (onSlotAdded) onSlotAdded(newSlot);
      } else {
        setError('Failed to create availability slot');
      }
    } catch (err) {
      setError('An error occurred while creating the slot');
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteSlot = (slotId: string) => {
    setError(null);

    if (deleteAvailabilitySlot(slotId)) {
      setSlots(slots.filter(slot => slot.id !== slotId));
      if (onSlotDeleted) onSlotDeleted(slotId);
    } else {
      setError('Failed to delete the slot');
    }
  };

  const handleEditSlot = (slotId: string) => {
    const slot = slots.find(s => s.id === slotId);
    if (slot) {
      setSelectedDay(slot.dayOfWeek);
      setStartTime(slot.startTime);
      setEndTime(slot.endTime);
      setEditingSlotId(slotId);
    }
  };

  const handleUpdateSlot = () => {
    if (!editingSlotId) return;

    setError(null);
    setIsLoading(true);

    try {
      if (!validateTimeFormat(startTime) || !validateTimeFormat(endTime)) {
        setError('Invalid time format');
        return;
      }

      if (!isValidTimeRange(startTime, endTime)) {
        setError('Start time must be before end time');
        return;
      }

      const updatedSlot = updateAvailabilitySlot(editingSlotId, {
        dayOfWeek: selectedDay as any,
        startTime,
        endTime
      });

      if (updatedSlot) {
        setSlots(slots.map(slot => (slot.id === editingSlotId ? updatedSlot : slot)));
        setEditingSlotId(null);
        setStartTime('09:00');
        setEndTime('10:00');
        if (onSlotUpdated) onSlotUpdated(updatedSlot);
      } else {
        setError('Failed to update the slot');
      }
    } catch (err) {
      setError('An error occurred while updating the slot');
    } finally {
      setIsLoading(false);
    }
  };

  const handleCancel = () => {
    setEditingSlotId(null);
    setSelectedDay('Monday');
    setStartTime('09:00');
    setEndTime('10:00');
    setError(null);
  };

  const slotsForDay = slots.filter(slot => slot.dayOfWeek === selectedDay).sort((a, b) => {
    return a.startTime.localeCompare(b.startTime);
  });

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <h2 className="text-lg font-medium text-gray-900">Add Availability</h2>
        </CardHeader>
        <CardBody className="space-y-4">
          {error && (
            <div className="bg-error-50 border border-error-200 rounded-lg p-3 flex items-start">
              <AlertCircle size={18} className="text-error-600 mr-2 mt-0.5 flex-shrink-0" />
              <p className="text-sm text-error-700">{error}</p>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Day of Week
              </label>
              <select
                value={selectedDay}
                onChange={(e) => setSelectedDay(e.target.value)}
                className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 sm:text-sm"
              >
                {DAYS_OF_WEEK.map(day => (
                  <option key={day} value={day}>{day}</option>
                ))}
              </select>
            </div>

            <Input
              label="Start Time"
              type="time"
              value={startTime}
              onChange={(e) => setStartTime(e.target.value)}
              startAdornment={<Clock size={18} />}
            />

            <Input
              label="End Time"
              type="time"
              value={endTime}
              onChange={(e) => setEndTime(e.target.value)}
              startAdornment={<Clock size={18} />}
            />
          </div>

          <div className="flex gap-2">
            <Button
              onClick={editingSlotId ? handleUpdateSlot : handleAddSlot}
              isLoading={isLoading}
              leftIcon={editingSlotId ? <Edit2 size={18} /> : <Plus size={18} />}
            >
              {editingSlotId ? 'Update Slot' : 'Add Slot'}
            </Button>

            {editingSlotId && (
              <Button
                variant="outline"
                onClick={handleCancel}
              >
                Cancel
              </Button>
            )}
          </div>
        </CardBody>
      </Card>

      {/* Existing slots for selected day */}
      <Card>
        <CardHeader className="flex justify-between items-center">
          <h3 className="text-lg font-medium text-gray-900">{selectedDay} Slots</h3>
          <Badge variant="primary">{slotsForDay.length} slot(s)</Badge>
        </CardHeader>
        <CardBody>
          {slotsForDay.length > 0 ? (
            <div className="space-y-3">
              {slotsForDay.map(slot => (
                <div
                  key={slot.id}
                  className="flex items-center justify-between p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  <div className="flex items-center space-x-4">
                    <div className="p-2 bg-primary-50 rounded-lg">
                      <Clock size={18} className="text-primary-600" />
                    </div>
                    <div>
                      <p className="font-medium text-gray-900">
                        {slot.startTime} - {slot.endTime}
                      </p>
                      <p className="text-sm text-gray-500">{slot.dayOfWeek}</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleEditSlot(slot.id)}
                      leftIcon={<Edit2 size={16} />}
                    >
                      Edit
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="text-error-600 hover:text-error-700"
                      onClick={() => handleDeleteSlot(slot.id)}
                      leftIcon={<Trash2 size={16} />}
                    >
                      Delete
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-6">
              <Clock size={24} className="mx-auto text-gray-400 mb-2" />
              <p className="text-gray-600">No availability slots for {selectedDay}</p>
            </div>
          )}
        </CardBody>
      </Card>

      {/* All slots summary */}
      <Card>
        <CardHeader>
          <h3 className="text-lg font-medium text-gray-900">All Availability</h3>
        </CardHeader>
        <CardBody>
          {slots.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
              {DAYS_OF_WEEK.map(day => {
                const daySlots = slots.filter(slot => slot.dayOfWeek === day);
                return (
                  <div key={day} className="p-3 border border-gray-200 rounded-lg">
                    <p className="font-medium text-gray-900 text-sm mb-2">{day}</p>
                    {daySlots.length > 0 ? (
                      <div className="space-y-1">
                        {daySlots.map(slot => (
                          <p key={slot.id} className="text-xs text-gray-600">
                            {slot.startTime} - {slot.endTime}
                          </p>
                        ))}
                      </div>
                    ) : (
                      <p className="text-xs text-gray-500 italic">No slots</p>
                    )}
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-6">
              <p className="text-gray-600">Add your first availability slot above</p>
            </div>
          )}
        </CardBody>
      </Card>
    </div>
  );
};

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { ConfirmedMeeting } from '../../types';
import { Card, CardHeader, CardBody } from '../ui/Card';
import { Button } from '../ui/Button';

interface CalendarProps {
  meetings: ConfirmedMeeting[];
  onDateSelect?: (date: string) => void;
  onEventClick?: (meeting: ConfirmedMeeting) => void;
}

export const Calendar: React.FC<CalendarProps> = ({ meetings, onDateSelect, onEventClick }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  const daysInMonth = (date: Date) => {
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  };

  const firstDayOfMonth = (date: Date) => {
    return new Date(date.getFullYear(), date.getMonth(), 1).getDay();
  };

  const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });
  const totalDays = daysInMonth(currentDate);
  const firstDay = firstDayOfMonth(currentDate);

  const previousMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const getMeetingsForDate = (day: number) => {
    return meetings.filter(meeting => {
      const meetingDate = new Date(meeting.date);
      return meetingDate.getDate() === day &&
             meetingDate.getMonth() === currentDate.getMonth() &&
             meetingDate.getFullYear() === currentDate.getFullYear();
    });
  };

  const days = [];
  for (let i = 0; i < firstDay; i++) {
    days.push(null);
  }
  for (let i = 1; i <= totalDays; i++) {
    days.push(i);
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <h2 className="text-lg font-medium text-gray-900">{monthName}</h2>
          <div className="flex space-x-2">
            <Button
              variant="outline"
              size="sm"
              onClick={previousMonth}
            >
              <ChevronLeft size={16} />
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={nextMonth}
            >
              <ChevronRight size={16} />
            </Button>
          </div>
        </div>
      </CardHeader>
      
      <CardBody>
        <div className="space-y-4">
          {/* Days of week header */}
          <div className="grid grid-cols-7 gap-2 mb-4">
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
              <div key={day} className="text-center text-sm font-semibold text-gray-600 py-2">
                {day}
              </div>
            ))}
          </div>
          
          {/* Calendar grid */}
          <div className="grid grid-cols-7 gap-2">
            {days.map((day, index) => {
              const dayMeetings = day ? getMeetingsForDate(day) : [];
              return (
                <div
                  key={index}
                  className="aspect-square border border-gray-200 rounded-lg p-1 bg-white hover:bg-gray-50 cursor-pointer transition-colors"
                  onClick={() => {
                    if (day && onDateSelect) {
                      const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
                      onDateSelect(date.toISOString().split('T')[0]);
                    }
                  }}
                >
                  <div className="h-full flex flex-col">
                    {day && (
                      <>
                        <div className="text-sm font-medium text-gray-900">{day}</div>
                        <div className="flex-1 overflow-y-auto">
                          {dayMeetings.slice(0, 2).map(meeting => (
                            <div
                              key={meeting.id}
                              className="text-xs bg-primary-100 text-primary-700 px-1 py-0.5 rounded mb-0.5 truncate cursor-pointer hover:bg-primary-200"
                              onClick={(e) => {
                                e.stopPropagation();
                                if (onEventClick) onEventClick(meeting);
                              }}
                              title={meeting.title}
                            >
                              {meeting.title}
                            </div>
                          ))}
                          {dayMeetings.length > 2 && (
                            <div className="text-xs text-gray-500">
                              +{dayMeetings.length - 2} more
                            </div>
                          )}
                        </div>
                      </>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </CardBody>
    </Card>
  );
};

import React, { useMemo } from 'react';
import { Link } from 'react-router-dom';
import { Calendar, Clock, Users, MapPin, Video, Phone, ArrowRight } from 'lucide-react';
import { ConfirmedMeeting } from '../../types';
import { Button } from '../ui/Button';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Badge } from '../ui/Badge';
import { Avatar } from '../ui/Avatar';
import { findUserById } from '../../data/users';

interface ConfirmedMeetingsWidgetProps {
  meetings: ConfirmedMeeting[];
  currentUserId: string;
  onMeetingClick?: (meeting: ConfirmedMeeting) => void;
  showViewAll?: boolean;
  limit?: number;
}

export const ConfirmedMeetingsWidget: React.FC<ConfirmedMeetingsWidgetProps> = ({
  meetings,
  currentUserId,
  onMeetingClick,
  showViewAll = true,
  limit = 3
}) => {
  // Sort and limit meetings
  const displayedMeetings = useMemo(() => {
    return meetings
      .sort((a, b) => {
        const dateA = new Date(`${a.date}T${a.startTime}`).getTime();
        const dateB = new Date(`${b.date}T${b.startTime}`).getTime();
        return dateA - dateB;
      })
      .slice(0, limit);
  }, [meetings, limit]);

  const getMeetingTypeIcon = (type: string) => {
    switch (type) {
      case 'video':
        return <Video size={16} className="text-blue-600" />;
      case 'call':
        return <Phone size={16} className="text-green-600" />;
      case 'in-person':
        return <MapPin size={16} className="text-orange-600" />;
      default:
        return <Calendar size={16} className="text-gray-600" />;
    }
  };

  const getMeetingTypeLabel = (type: string) => {
    return type.charAt(0).toUpperCase() + type.slice(1).replace('-', ' ');
  };

  const getOtherParticipants = (meeting: ConfirmedMeeting) => {
    return meeting.participantIds.filter(id => id !== currentUserId);
  };

  const formatDateTime = (date: string, time: string) => {
    const dateObj = new Date(`${date}T${time}`);
    return dateObj.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      weekday: 'short'
    });
  };

  return (
    <Card>
      <CardHeader className="flex justify-between items-center">
        <h2 className="text-lg font-medium text-gray-900">Confirmed Meetings</h2>
        <Badge variant="primary">{meetings.length} scheduled</Badge>
      </CardHeader>
      
      <CardBody>
        {displayedMeetings.length > 0 ? (
          <div className="space-y-3">
            {displayedMeetings.map(meeting => {
              const otherParticipants = getOtherParticipants(meeting);
              const firstParticipant = otherParticipants.length > 0 
                ? findUserById(otherParticipants[0])
                : null;

              return (
                <div
                  key={meeting.id}
                  className="p-4 border border-gray-200 rounded-lg hover:border-primary-300 hover:bg-primary-50 transition-colors cursor-pointer"
                  onClick={() => onMeetingClick?.(meeting)}
                >
                  <div className="flex items-start justify-between gap-3 mb-3">
                    {/* Meeting title and type */}
                    <div className="flex-1 min-w-0">
                      <h3 className="font-medium text-gray-900 truncate">
                        {meeting.title}
                      </h3>
                      <div className="flex items-center gap-2 mt-1">
                        {getMeetingTypeIcon(meeting.meetingType)}
                        <span className="text-xs text-gray-600">
                          {getMeetingTypeLabel(meeting.meetingType)}
                        </span>
                      </div>
                    </div>

                    {/* Participants count */}
                    <Badge variant="secondary" size="sm">
                      <Users size={14} className="mr-1" />
                      {meeting.participantIds.length}
                    </Badge>
                  </div>

                  {/* Date and time */}
                  <div className="flex items-center gap-4 mb-3 text-sm text-gray-600">
                    <div className="flex items-center gap-1">
                      <Calendar size={14} className="text-gray-400" />
                      <span>{formatDateTime(meeting.date, meeting.startTime)}</span>
                    </div>
                    <div className="flex items-center gap-1">
                      <Clock size={14} className="text-gray-400" />
                      <span>{meeting.startTime} - {meeting.endTime}</span>
                    </div>
                  </div>

                  {/* Location or meeting details */}
                  {(meeting.location || otherParticipants.length > 0) && (
                    <div className="flex items-center gap-2 mb-3 text-sm">
                      {firstParticipant && (
                        <div className="flex items-center gap-2">
                          <Avatar
                            src={firstParticipant.avatarUrl}
                            alt={firstParticipant.name}
                            size="sm"
                          />
                          <span className="text-gray-700 truncate">
                            {firstParticipant.name}
                            {otherParticipants.length > 1 && ` +${otherParticipants.length - 1}`}
                          </span>
                        </div>
                      )}
                    </div>
                  )}

                  {/* Description preview */}
                  {meeting.description && (
                    <p className="text-sm text-gray-600 mb-3 line-clamp-2">
                      {meeting.description}
                    </p>
                  )}

                  {/* Location if in-person */}
                  {meeting.location && (
                    <div className="flex items-center gap-2 text-sm text-gray-600 mb-3">
                      <MapPin size={14} className="text-gray-400" />
                      <span>{meeting.location}</span>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ) : (
          <div className="text-center py-8">
            <Calendar size={32} className="mx-auto text-gray-400 mb-3" />
            <p className="text-gray-600">No confirmed meetings yet</p>
            <p className="text-sm text-gray-500 mt-1">Send a meeting request to schedule one</p>
          </div>
        )}

        {/* View all button */}
        {showViewAll && meetings.length > limit && (
          <div className="mt-4 pt-4 border-t border-gray-200">
            <Link to="/calendar" className="block">
              <Button
                variant="outline"
                fullWidth
                rightIcon={<ArrowRight size={18} />}
              >
                View All Meetings
              </Button>
            </Link>
          </div>
        )}
      </CardBody>
    </Card>
  );
};

import React, { useState } from 'react';
import { Calendar, Clock, User, MessageCircle, Check, X, AlertCircle } from 'lucide-react';
import { MeetingRequest } from '../../types';
import { Button } from '../ui/Button';
import { Card, CardBody } from '../ui/Card';
import { Badge } from '../ui/Badge';
import { Avatar } from '../ui/Avatar';
import {
  acceptMeetingRequest,
  declineMeetingRequest,
  cancelMeetingRequest
} from '../../data/meetingRequests';
import { findUserById } from '../../data/users';

interface MeetingRequestCardProps {
  request: MeetingRequest;
  currentUserId: string;
  onStatusChange?: (request: MeetingRequest) => void;
}

export const MeetingRequestCard: React.FC<MeetingRequestCardProps> = ({
  request,
  currentUserId,
  onStatusChange
}) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isRequester = request.requesterId === currentUserId;
  const otherUser = isRequester
    ? findUserById(request.recipientId)
    : findUserById(request.requesterId);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending':
        return 'accent';
      case 'accepted':
        return 'success';
      case 'declined':
        return 'error';
      case 'cancelled':
        return 'gray';
      default:
        return 'gray';
    }
  };

  const getStatusLabel = (status: string) => {
    return status.charAt(0).toUpperCase() + status.slice(1);
  };

  const handleAccept = async () => {
    setError(null);
    setIsLoading(true);

    try {
      const updated = acceptMeetingRequest(request.id);
      if (updated && onStatusChange) {
        onStatusChange(updated);
      } else {
        setError('Failed to accept meeting request');
      }
    } catch (err) {
      setError('An error occurred while accepting the request');
    } finally {
      setIsLoading(false);
    }
  };

  const handleDecline = async () => {
    setError(null);
    setIsLoading(true);

    try {
      const updated = declineMeetingRequest(request.id);
      if (updated && onStatusChange) {
        onStatusChange(updated);
      } else {
        setError('Failed to decline meeting request');
      }
    } catch (err) {
      setError('An error occurred while declining the request');
    } finally {
      setIsLoading(false);
    }
  };

  const handleCancel = async () => {
    setError(null);
    setIsLoading(true);

    try {
      const updated = cancelMeetingRequest(request.id);
      if (updated && onStatusChange) {
        onStatusChange(updated);
      } else {
        setError('Failed to cancel meeting request');
      }
    } catch (err) {
      setError('An error occurred while cancelling the request');
    } finally {
      setIsLoading(false);
    }
  };

  if (!otherUser) {
    return null;
  }

  return (
    <Card className={`border-l-4 ${
      request.status === 'pending'
        ? 'border-l-accent-500 bg-accent-50'
        : request.status === 'accepted'
        ? 'border-l-success-500 bg-success-50'
        : 'border-l-gray-300'
    }`}>
      <CardBody className="p-4">
        {error && (
          <div className="mb-4 bg-error-50 border border-error-200 rounded-lg p-3 flex items-start">
            <AlertCircle size={18} className="text-error-600 mr-2 mt-0.5 flex-shrink-0" />
            <p className="text-sm text-error-700">{error}</p>
          </div>
        )}

        <div className="flex items-start justify-between gap-4">
          {/* Left section - User info and meeting details */}
          <div className="flex items-start space-x-4 flex-1 min-w-0">
            <Avatar
              src={otherUser.avatarUrl}
              alt={otherUser.name}
              size="md"
              status={otherUser.isOnline ? 'online' : 'offline'}
              className="flex-shrink-0"
            />

            <div className="flex-1 min-w-0">
              {/* Header with user name and status */}
              <div className="flex items-center gap-2 mb-2">
                <h3 className="text-base font-medium text-gray-900 truncate">
                  {isRequester ? 'Your request to' : 'Request from'} {otherUser.name}
                </h3>
                <Badge variant={getStatusColor(request.status)} size="sm">
                  {getStatusLabel(request.status)}
                </Badge>
              </div>

              {/* Meeting title */}
              <p className="text-sm font-medium text-gray-900 mb-2">
                {request.title}
              </p>

              {/* Description */}
              {request.description && (
                <p className="text-sm text-gray-600 mb-3 line-clamp-2">
                  {request.description}
