                </div>

                <div className="flex items-center gap-2">
                  <Clock size={16} className="text-gray-500 flex-shrink-0" />
                  <span className="text-sm text-gray-600">
                    {request.proposedStartTime} - {request.proposedEndTime}
                  </span>
