                  </button>

                  {isProfileOpen && (
                    <div className="absolute right-0 top-full z-20 mt-2 w-48 overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-lg ring-1 ring-black ring-opacity-5">
                      <Link
                        to={profileRoute}
                        className="flex items-center gap-2 px-4 py-3 text-sm text-gray-700 hover:bg-gray-50"
                        onClick={() => setIsProfileOpen(false)}
                      >
                        <User size={16} />
                        View profile
                      </Link>
                      <Link
                        to="/settings"
                        className="flex items-center gap-2 px-4 py-3 text-sm text-gray-700 hover:bg-gray-50"
                        onClick={() => setIsProfileOpen(false)}
                      >
                        <Settings size={16} />
                        Settings
                      </Link>
                      <button
                        type="button"
                        onClick={handleLogout}
                        className="w-full flex items-center gap-2 px-4 py-3 text-sm text-gray-700 hover:bg-gray-50"
                      >
                        <LogOut size={16} />
                        Logout
                      </button>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div className="flex items-center gap-3">
                <Link to="/login">
                  <Button variant="outline">Log in</Button>
                </Link>
                <Link to="/register">
                  <Button>Sign up</Button>
                </Link>
              </div>
            )}
          </div>
          
          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={toggleMenu}
              className="inline-flex items-center justify-center p-2 rounded-md text-gray-700 hover:text-primary-600 hover:bg-gray-50 focus:outline-none"
            >
              {isMenuOpen ? (
                <X className="block h-6 w-6" />
              ) : (
                <Menu className="block h-6 w-6" />
              )}
            </button>
          </div>
        </div>
      </div>
      
      {/* Mobile menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-white border-b border-gray-200 animate-fade-in">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {user ? (
              <>
                <div className="flex items-center space-x-3 px-3 py-2">
                  <Avatar
                    src={user.avatarUrl}
                    alt={user.name}
                    size="sm"
                    status={user.isOnline ? 'online' : 'offline'}
                  />
                  <div>
                    <p className="text-sm font-medium text-gray-800">{user.name}</p>
                    <p className="text-xs text-gray-500 capitalize">{user.role}</p>
                  </div>
                </div>
                
                <div className="border-t border-gray-200 pt-2">
                  {navLinks.map((link, index) => (
                    <Link
                      key={index}
                      to={link.path}
                      data-tour={link.tourId}
                      className="flex items-center px-3 py-2 text-base font-medium text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md"
                      onClick={() => setIsMenuOpen(false)}
                    >
                      <span className="mr-3">{link.icon}</span>
                      {link.text}
                    </Link>
                  ))}
                  
                  <button
                    onClick={() => {
                      handleLogout();
                      setIsMenuOpen(false);
                    }}
                    className="flex w-full items-center px-3 py-2 text-base font-medium text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md"
                  >
                    <LogOut size={18} className="mr-3" />
                    Logout
                  </button>
                </div>
              </>
            ) : (
              <div className="flex flex-col space-y-2 px-3 py-2">
                <Link 
                  to="/login" 
                  className="w-full"
                  onClick={() => setIsMenuOpen(false)}
                >
                  <Button variant="outline" fullWidth>Log in</Button>
                </Link>
                <Link 
                  to="/register" 
                  className="w-full"
                  onClick={() => setIsMenuOpen(false)}
                >
                  <Button fullWidth>Sign up</Button>
                </Link>
              </div>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

import React, { useState } from 'react';
import { TrendingUp, CheckCircle } from 'lucide-react';
import { Link } from 'react-router-dom';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import { Deal } from '../../types';

interface DealFundingCardProps {
  deal: Deal;
  onFundClick?: (dealId: string) => void;
}

export const DealFundingCard: React.FC<DealFundingCardProps> = ({
  deal,
  onFundClick,
}) => {
  const fundingPercentage = Math.round((deal.fundingAmount / deal.fundingTarget) * 100);
  const remainingAmount = deal.fundingTarget - deal.fundingAmount;

  const getStatusColor = (status: string): 'success' | 'warning' | 'primary' | 'gray' => {
    switch (status) {
      case 'funded':
        return 'success';
      case 'open':
        return 'primary';
      case 'rejected':
        return 'error';
      default:
        return 'gray';
    }
  };

  return (
    <Card className="overflow-hidden hover:shadow-lg transition-shadow">
      <CardBody className="space-y-4">
        {/* Header */}
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1">
            <h3 className="text-lg font-semibold text-gray-900">{deal.title}</h3>
            <p className="text-sm text-gray-600 mt-1">{deal.description}</p>
          </div>
          <Badge variant={getStatusColor(deal.status)}>
            {deal.status === 'funded' && <CheckCircle size={14} className="inline mr-1" />}
            {deal.status.charAt(0).toUpperCase() + deal.status.slice(1)}
          </Badge>
        </div>

        {/* Equity Info */}
        <div className="bg-primary-50 rounded-lg p-3">
          <div className="flex items-center justify-between">
            <span className="text-sm font-medium text-primary-900">Equity Offering</span>
            <span className="text-lg font-bold text-primary-700">{deal.equity}%</span>
          </div>
        </div>

        {/* Funding Progress */}
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-sm font-medium text-gray-700">Funding Progress</span>
            <span className="text-sm font-semibold text-gray-900">{fundingPercentage}%</span>
          </div>

          {/* Progress Bar */}
          <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
            <div
              className="bg-gradient-to-r from-primary-500 to-primary-600 h-full transition-all duration-300"
              style={{ width: `${fundingPercentage}%` }}
            />
          </div>

          {/* Funding Details */}
          <div className="flex items-center justify-between text-sm">
            <span className="text-gray-600">
              ${deal.fundingAmount.toLocaleString()} of ${deal.fundingTarget.toLocaleString()}
            </span>
            <span className="text-gray-600">
              ${remainingAmount.toLocaleString()} remaining
            </span>
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 gap-2">
          <div className="bg-gray-50 rounded-lg p-2">
            <p className="text-xs text-gray-600">Target</p>
            <p className="text-sm font-semibold text-gray-900">
              ${deal.fundingTarget.toLocaleString()} {deal.currency}
            </p>
          </div>
          <div className="bg-gray-50 rounded-lg p-2">
            <p className="text-xs text-gray-600">Raised</p>
            <p className="text-sm font-semibold text-gray-900">
              ${deal.fundingAmount.toLocaleString()} {deal.currency}
            </p>
          </div>
        </div>

        {/* Action Button */}
        {deal.status === 'open' ? (
          <Button
            variant="primary"
            fullWidth
            leftIcon={<TrendingUp size={18} />}
            onClick={() => onFundClick?.(deal.id)}
          >
            Fund This Deal
          </Button>
        ) : (
          <Button
            variant="outline"
            fullWidth
            disabled
          >
            {deal.status === 'funded' ? 'Γ£ô Fully Funded' : 'Deal Closed'}
          </Button>
        )}
      </CardBody>
    </Card>
  );
};

import React, { useState } from 'react';
import { X, TrendingUp } from 'lucide-react';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import toast from 'react-hot-toast';
import { Deal, Transaction } from '../../types';

interface DealFundingModalProps {
  deal: Deal;
  isOpen: boolean;
  userBalance: number;
  onClose: () => void;
  onFundingSuccess?: (transaction: Transaction) => void;
}

export const DealFundingModal: React.FC<DealFundingModalProps> = ({
  deal,
  isOpen,
  userBalance,
  onClose,
  onFundingSuccess,
}) => {
  const [investmentAmount, setInvestmentAmount] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const remainingTarget = deal.fundingTarget - deal.fundingAmount;
  const maxInvestment = Math.min(userBalance, remainingTarget);

  const handleFunding = async (e: React.FormEvent) => {
    e.preventDefault();

    const amount = parseFloat(investmentAmount);

    if (!investmentAmount || amount <= 0) {
      toast.error('Please enter a valid amount');
      return;
    }

    if (amount > userBalance) {
      toast.error(`Insufficient balance. Available: $${userBalance.toFixed(2)}`);
      return;
    }

    if (amount > remainingTarget) {
      toast.error(`Cannot invest more than remaining target: $${remainingTarget.toFixed(2)}`);
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Create transaction
      const transaction: Transaction = {
        id: `t${Date.now()}`,
        walletId: `w${Date.now()}`,
        userId: `i${Date.now()}`,
        type: 'investment',
        status: 'completed',
        amount,
        currency: 'USD',
        description: `Investment in ${deal.title}`,
        dealId: deal.id,
        relatedUserId: deal.entrepreneurId,
        reference: `INVEST-${Date.now().toString().slice(-6)}`,
        createdAt: new Date().toISOString(),
        completedAt: new Date().toISOString(),
      };

      if (onFundingSuccess) {
        onFundingSuccess(transaction);
      }

      toast.success(`Successfully invested $${amount.toFixed(2)} in ${deal.title}!`);
      setInvestmentAmount('');
      onClose();
    } catch (error) {
      toast.error('Investment failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-lg shadow-xl max-w-md w-full max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="sticky top-0 bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between">
          <h2 className="text-xl font-bold text-gray-900">Fund Deal</h2>
          <button
            onClick={onClose}
            className="text-gray-500 hover:text-gray-700"
          >
            <X size={24} />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 space-y-4">
          {/* Deal Summary */}
          <div className="bg-primary-50 border border-primary-200 rounded-lg p-4 space-y-2">
            <h3 className="font-semibold text-gray-900">{deal.title}</h3>
            <p className="text-sm text-gray-600">{deal.description}</p>
            
            <div className="pt-2 border-t border-primary-200 space-y-1">
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-700">Equity Offering:</span>
                <Badge variant="primary">{deal.equity}%</Badge>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-700">Remaining:</span>
                <span className="font-semibold text-primary-700">
                  ${remainingTarget.toLocaleString()}
                </span>
              </div>
            </div>
          </div>

          {/* Investment Form */}
          <form onSubmit={handleFunding} className="space-y-4">
            {/* Investment Amount */}
            <Input
              label="Investment Amount (USD)"
              type="number"
              placeholder="0.00"
              value={investmentAmount}
              onChange={(e) => setInvestmentAmount(e.target.value)}
              min="0"
              step="0.01"
              max={maxInvestment}
              fullWidth
              startAdornment="$"
              required
            />

            {/* Quick Amount Buttons */}
            <div className="space-y-2">
              <span className="text-xs text-gray-600">Quick amounts:</span>
              <div className="flex flex-wrap gap-2">
                {[10000, 25000, 50000].map((amount) => (
                  <button
                    key={amount}
                    type="button"
                    onClick={() => setInvestmentAmount(Math.min(amount, maxInvestment).toString())}
                    className="px-3 py-1 text-sm border border-gray-300 rounded hover:bg-gray-50 transition-colors"
                    disabled={amount > maxInvestment}
                  >
                    ${amount.toLocaleString()}
                  </button>
                ))}
              </div>
            </div>

            {/* Investment Summary */}
            {investmentAmount && (
              <div className="bg-success-50 border border-success-200 rounded-lg p-3 space-y-2">
                <p className="text-sm font-medium text-success-900">Investment Summary</p>
                <div className="space-y-1 text-sm text-success-800">
                  <div className="flex justify-between">
                    <span>Investment Amount:</span>
                    <span className="font-semibold">${parseFloat(investmentAmount).toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Your Equity Share:</span>
                    <span className="font-semibold">
                      {((parseFloat(investmentAmount) / deal.fundingTarget) * deal.equity).toFixed(2)}%
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span>New Balance:</span>
                    <span className="font-semibold">
                      ${(userBalance - parseFloat(investmentAmount)).toFixed(2)}
                    </span>
                  </div>
                </div>
              </div>
            )}

            {/* Info Box */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
              <p className="text-sm text-blue-800">
                <span className="font-medium">≡ƒÆí Mock Mode:</span> This is a simulation. Investment will be recorded but no actual funds are transferred.
              </p>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-3 pt-2">
              <Button
                variant="outline"
                fullWidth
                onClick={onClose}
                disabled={isLoading}
              >
                Cancel
              </Button>
              <Button
                variant="primary"
                fullWidth
                isLoading={isLoading}
                leftIcon={<TrendingUp size={18} />}
                type="submit"
              >
                {isLoading ? 'Processing...' : 'Invest Now'}
              </Button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CreditCard } from 'lucide-react';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import toast from 'react-hot-toast';
import { Transaction } from '../../types';

interface DepositFormProps {
  userId: string;
  walletId: string;
  onDepositSuccess?: (transaction: Transaction) => void;
}

export const DepositForm: React.FC<DepositFormProps> = ({
  userId,
  walletId,
  onDepositSuccess,
}) => {
  const [amount, setAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('credit_card');
  const [description, setDescription] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const paymentMethods = [
    { id: 'credit_card', label: 'Credit Card', icon: '≡ƒÆ│' },
    { id: 'debit_card', label: 'Debit Card', icon: '≡ƒÅª' },
    { id: 'bank_transfer', label: 'Bank Transfer', icon: '≡ƒÅó' },
  ];

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!amount || parseFloat(amount) <= 0) {
      toast.error('Please enter a valid amount');
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Create transaction object
      const newTransaction: Transaction = {
        id: `t${Date.now()}`,
        walletId,
        userId,
        type: 'deposit',
        status: 'completed',
        amount: parseFloat(amount),
        currency: 'USD',
        description: description || 'Deposit via ' + paymentMethods.find(m => m.id === paymentMethod)?.label,
        paymentMethodId: `pm${Date.now()}`,
        reference: `TXN-${Date.now().toString().slice(-6)}`,
        createdAt: new Date().toISOString(),
        completedAt: new Date().toISOString(),
      };

      // Call success callback
      if (onDepositSuccess) {
        onDepositSuccess(newTransaction);
      }

      toast.success(`Deposit of $${parseFloat(amount).toFixed(2)} completed successfully!`);
      setAmount('');
      setDescription('');
    } catch (error) {
      toast.error('Deposit failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader className="border-b border-gray-200">
        <h3 className="text-lg font-semibold text-gray-900">Deposit Funds</h3>
      </CardHeader>

      <CardBody>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Amount */}
          <Input
            label="Amount (USD)"
            type="number"
            placeholder="0.00"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            min="0"
            step="0.01"
            fullWidth
            startAdornment="$"
            required
          />

          {/* Payment Method Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-3">
              Payment Method
            </label>
            <div className="grid grid-cols-3 gap-3">
              {paymentMethods.map((method) => (
                <button
                  key={method.id}
                  type="button"
                  onClick={() => setPaymentMethod(method.id)}
                  className={`p-3 rounded-lg border-2 transition-colors text-center ${
                    paymentMethod === method.id
                      ? 'border-primary-600 bg-primary-50'
                      : 'border-gray-200 bg-gray-50 hover:border-gray-300'
                  }`}
                >
                  <div className="text-lg mb-1">{method.icon}</div>
                  <p className="text-xs font-medium text-gray-700">{method.label}</p>
                </button>
              ))}
            </div>
          </div>

          {/* Description */}
          <Input
            label="Description (Optional)"
            placeholder="e.g., Monthly fund allocation"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            fullWidth
          />

          {/* Info Box */}
          <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
            <p className="text-sm text-blue-800">
              <span className="font-medium">≡ƒÆí Mock Mode:</span> This is a simulation. No actual payment will be processed. The transaction will be marked as completed.
            </p>
          </div>

          {/* Submit Button */}
          <Button
            variant="primary"
            fullWidth
            isLoading={isLoading}
            leftIcon={<CreditCard size={18} />}
            type="submit"
          >
            {isLoading ? 'Processing...' : 'Deposit Now'}
          </Button>
        </form>
      </CardBody>
    </Card>
  );
};

import React, { useState } from 'react';
import { Send } from 'lucide-react';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import toast from 'react-hot-toast';
import { Transaction, User } from '../../types';

interface TransferFormProps {
  userId: string;
  walletId: string;
  currentBalance: number;
  allUsers: User[];
  onTransferSuccess?: (transaction: Transaction) => void;
}

export const TransferForm: React.FC<TransferFormProps> = ({
  userId,
  walletId,
  currentBalance,
  allUsers,
  onTransferSuccess,
}) => {
  const [amount, setAmount] = useState('');
  const [selectedUserId, setSelectedUserId] = useState('');
  const [description, setDescription] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Filter out current user
  const otherUsers = allUsers.filter(u => u.id !== userId);
  const selectedUser = otherUsers.find(u => u.id === selectedUserId);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const transferAmount = parseFloat(amount);

    if (!amount || transferAmount <= 0) {
      toast.error('Please enter a valid amount');
      return;
    }

    if (transferAmount > currentBalance) {
      toast.error(`Insufficient balance. Available: $${currentBalance.toFixed(2)}`);
      return;
    }

    if (!selectedUserId) {
      toast.error('Please select a recipient');
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Create transaction object
      const newTransaction: Transaction = {
        id: `t${Date.now()}`,
        walletId,
        userId,
        type: 'transfer',
        status: 'completed',
        amount: transferAmount,
        currency: 'USD',
        description: description || `Transfer to ${selectedUser?.name}`,
        relatedUserId: selectedUserId,
        reference: `TRF-${Date.now().toString().slice(-6)}`,
        createdAt: new Date().toISOString(),
        completedAt: new Date().toISOString(),
      };

      // Call success callback
      if (onTransferSuccess) {
        onTransferSuccess(newTransaction);
      }

      toast.success(`Transfer of $${transferAmount.toFixed(2)} to ${selectedUser?.name} completed!`);
      setAmount('');
      setSelectedUserId('');
      setDescription('');
    } catch (error) {
      toast.error('Transfer failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader className="border-b border-gray-200">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-semibold text-gray-900">Transfer Funds</h3>
          <p className="text-sm text-gray-600">
            Balance: <span className="font-semibold">${currentBalance.toFixed(2)}</span>
          </p>
        </div>
      </CardHeader>

      <CardBody>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Recipient Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Transfer To
            </label>
            <select
              value={selectedUserId}
              onChange={(e) => setSelectedUserId(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              required
            >
              <option value="">Select a recipient...</option>
              {otherUsers.map((user) => (
                <option key={user.id} value={user.id}>
                  {user.name} ({user.role === 'entrepreneur' ? '≡ƒÜÇ' : '≡ƒÆ╝'})
                </option>
              ))}
            </select>
          </div>

          {/* Selected User Preview */}
          {selectedUser && (
            <div className="bg-gray-50 border border-gray-200 rounded-lg p-3">
              <div className="flex items-center gap-3">
                <img
                  src={selectedUser.avatarUrl}
                  alt={selectedUser.name}
                  className="w-10 h-10 rounded-full object-cover"
