import React, { useState } from 'react';
import { ArrowUpRight } from 'lucide-react';
import { Card, CardBody, CardHeader } from '../ui/Card';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import toast from 'react-hot-toast';
import { Transaction } from '../../types';

interface WithdrawFormProps {
  userId: string;
  walletId: string;
  currentBalance: number;
  onWithdrawSuccess?: (transaction: Transaction) => void;
}

export const WithdrawForm: React.FC<WithdrawFormProps> = ({
  userId,
  walletId,
  currentBalance,
  onWithdrawSuccess,
}) => {
  const [amount, setAmount] = useState('');
  const [bankName, setBankName] = useState('');
  const [accountNumber, setAccountNumber] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const withdrawAmount = parseFloat(amount);

    if (!amount || withdrawAmount <= 0) {
      toast.error('Please enter a valid amount');
      return;
    }

    if (withdrawAmount > currentBalance) {
      toast.error(`Insufficient balance. Available: $${currentBalance.toFixed(2)}`);
      return;
    }

    if (!bankName.trim()) {
      toast.error('Please enter a bank name');
      return;
    }

    if (!accountNumber.trim()) {
      toast.error('Please enter an account number');
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Create transaction object
      const newTransaction: Transaction = {
        id: `t${Date.now()}`,
        walletId,
        userId,
        type: 'withdrawal',
        status: 'completed',
        amount: withdrawAmount,
        currency: 'USD',
        description: `Withdrawal to ${bankName} (*${accountNumber.slice(-4)})`,
        reference: `WITHDRAW-${Date.now().toString().slice(-6)}`,
        createdAt: new Date().toISOString(),
        completedAt: new Date().toISOString(),
      };

      // Call success callback
      if (onWithdrawSuccess) {
        onWithdrawSuccess(newTransaction);
      }

      toast.success(`Withdrawal of $${withdrawAmount.toFixed(2)} initiated successfully!`);
      setAmount('');
      setBankName('');
      setAccountNumber('');
    } catch (error) {
      toast.error('Withdrawal failed. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const maxWithdraw = currentBalance;
  const quickAmounts = [100, 500, 1000, 5000];

  return (
    <Card>
      <CardHeader className="border-b border-gray-200">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-semibold text-gray-900">Withdraw Funds</h3>
          <p className="text-sm text-gray-600">
            Balance: <span className="font-semibold">${maxWithdraw.toFixed(2)}</span>
          </p>
        </div>
      </CardHeader>

      <CardBody>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Amount */}
          <div>
            <Input
              label="Withdrawal Amount (USD)"
              type="number"
              placeholder="0.00"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              min="0"
              step="0.01"
              max={maxWithdraw}
              fullWidth
              startAdornment="$"
              required
            />

            {/* Quick Amount Buttons */}
            <div className="mt-3 flex flex-wrap gap-2">
              <span className="text-xs text-gray-600 w-full mb-1">Quick amounts:</span>
              {quickAmounts.map((quickAmount) => (
                <button
                  key={quickAmount}
                  type="button"
                  onClick={() => setAmount(quickAmount.toString())}
                  className="px-3 py-1 text-sm border border-gray-300 rounded hover:bg-gray-50 transition-colors"
                  disabled={quickAmount > maxWithdraw}
                >
                  ${quickAmount}
                </button>
              ))}
            </div>
          </div>

          {/* Bank Name */}
          <Input
            label="Bank Name"
            placeholder="e.g., Chase Bank, Bank of America"
            value={bankName}
            onChange={(e) => setBankName(e.target.value)}
            fullWidth
            required
          />

          {/* Account Number */}
          <Input
            label="Account Number"
            placeholder="Last 4 digits (will be masked)"
            type="password"
            value={accountNumber}
            onChange={(e) => setAccountNumber(e.target.value)}
            fullWidth
            required
          />

          {/* Info Box */}
          <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
            <p className="text-sm text-blue-800">
              <span className="font-medium">≡ƒÆí Mock Mode:</span> This is a simulation. No actual withdrawal will be processed.
            </p>
          </div>

          {/* Submit Button */}
          <Button
            variant="primary"
            fullWidth
            isLoading={isLoading}
            leftIcon={<ArrowUpRight size={18} />}
            type="submit"
          >
            {isLoading ? 'Processing...' : 'Withdraw Now'}
          </Button>
        </form>
      </CardBody>
    </Card>
  );
};

import React, { useRef, useState, useEffect } from 'react';

interface OTPInputProps {
  length?: number;
  value: string;
  onChange: (value: string) => void;
  onComplete?: (value: string) => void;
  disabled?: boolean;
  error?: string;
  autoFocus?: boolean;
}

export const OTPInput: React.FC<OTPInputProps> = ({
  length = 6,
  value,
  onChange,
  onComplete,
  disabled = false,
  error,
  autoFocus = true,
}) => {
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const [displayValue, setDisplayValue] = useState<string[]>(
    value.split('').slice(0, length)
  );

  useEffect(() => {
    setDisplayValue(value.split('').slice(0, length));
  }, [value, length]);

  useEffect(() => {
    if (autoFocus && inputRefs.current[0]) {
      inputRefs.current[0].focus();
    }
  }, [autoFocus]);

  const handleInputChange = (index: number, digit: string) => {
    // Only allow digits
    if (!/^\d*$/.test(digit)) return;

    const newValue = [...displayValue];
    newValue[index] = digit;

    // Remove leading zeros for single character
    if (digit && index < length) {
      const otp = newValue.join('');
      onChange(otp);
      setDisplayValue(newValue);

      // Auto-focus next input
      if (digit && index < length - 1) {
        inputRefs.current[index + 1]?.focus();
      }

      // Call onComplete when all digits are filled
      if (otp.length === length && onComplete) {
        onComplete(otp);
      }
    }
  };

  const handleKeyDown = (
    index: number,
    e: React.KeyboardEvent<HTMLInputElement>
  ) => {
    if (e.key === 'Backspace') {
      e.preventDefault();
      const newValue = [...displayValue];

      if (newValue[index]) {
        // Clear current input
        newValue[index] = '';
        setDisplayValue(newValue);
        onChange(newValue.join(''));
      } else if (index > 0) {
        // Move to previous input and clear it
        newValue[index - 1] = '';
        setDisplayValue(newValue);
        onChange(newValue.join(''));
        inputRefs.current[index - 1]?.focus();
      }
    } else if (e.key === 'ArrowLeft' && index > 0) {
      inputRefs.current[index - 1]?.focus();
    } else if (e.key === 'ArrowRight' && index < length - 1) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
    e.preventDefault();
    const pastedData = e.clipboardData.getData('text/plain');
    const digits = pastedData.replace(/\D/g, '').slice(0, length);

    if (digits) {
      setDisplayValue(digits.split('').slice(0, length));
      onChange(digits);

      if (digits.length === length && onComplete) {
        onComplete(digits);
      }

      // Focus last input or next empty one
      const nextIndex = Math.min(digits.length, length - 1);
      inputRefs.current[nextIndex]?.focus();
    }
  };

  return (
    <div className="space-y-2">
      <label className="block text-sm font-medium text-gray-700">
        Enter 6-Digit Code
      </label>

      <div className="flex justify-center gap-3">
        {Array.from({ length }).map((_, index) => (
          <input
            key={index}
            ref={(el) => {
              inputRefs.current[index] = el;
            }}
            type="text"
            inputMode="numeric"
            maxLength={1}
            value={displayValue[index] || ''}
            onChange={(e) => handleInputChange(index, e.target.value)}
            onKeyDown={(e) => handleKeyDown(index, e)}
            onPaste={handlePaste}
            disabled={disabled}
            className={`w-12 h-14 text-center text-xl font-bold border-2 rounded-lg transition-colors ${
              error
                ? 'border-error-500 bg-error-50 text-error-700'
                : 'border-gray-300 bg-white text-gray-900 focus:border-primary-500 focus:ring-2 focus:ring-primary-200'
            } ${disabled ? 'bg-gray-100 cursor-not-allowed' : ''}`}
            aria-label={`Digit ${index + 1}`}
          />
        ))}
      </div>

      {error && (
        <p className="text-sm text-error-600 text-center">
          {error}
        </p>
      )}

      {!error && (
        <p className="text-xs text-gray-500 text-center">
          Enter the 6-digit code sent to your email
        </p>
      )}
    </div>
  );
};

import React, { useMemo } from 'react';
import { Check, X } from 'lucide-react';
import { PasswordValidation, PasswordStrength } from '../../types';

interface PasswordStrengthMeterProps {
  password: string;
  showDetails?: boolean;
  className?: string;
}

export const validatePassword = (password: string): PasswordValidation => {
  const checks = {
    minLength: password.length >= 8,
    hasUppercase: /[A-Z]/.test(password),
    hasLowercase: /[a-z]/.test(password),
    hasNumber: /\d/.test(password),
    hasSpecialChar: /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password),
  };

  const passedChecks = Object.values(checks).filter(Boolean).length;
  let strength: PasswordStrength = 'weak';

  if (passedChecks >= 5) {
    strength = 'strong';
  } else if (passedChecks >= 3) {
    strength = 'medium';
  }

  const isValid = checks.minLength && checks.hasUppercase && checks.hasLowercase && checks.hasNumber;

  return {
    isValid,
    strength,
    checks,
  };
};

export const PasswordStrengthMeter: React.FC<PasswordStrengthMeterProps> = ({
  password,
  showDetails = true,
  className = '',
}) => {
  const validation = useMemo(() => validatePassword(password), [password]);
  const { strength, checks } = validation;

  const getStrengthColor = (str: PasswordStrength): string => {
    switch (str) {
      case 'strong':
        return 'bg-success-500';
      case 'medium':
        return 'bg-warning-500';
      case 'weak':
        return 'bg-error-500';
    }
  };

  const getStrengthLabel = (str: PasswordStrength): string => {
    switch (str) {
      case 'strong':
        return 'Strong';
      case 'medium':
        return 'Medium';
      case 'weak':
        return 'Weak';
    }
  };

  const getStrengthLabelColor = (str: PasswordStrength): string => {
    switch (str) {
      case 'strong':
        return 'text-success-700';
      case 'medium':
        return 'text-warning-700';
      case 'weak':
        return 'text-error-700';
    }
  };

  const CheckItem: React.FC<{ label: string; checked: boolean }> = ({ label, checked }) => (
    <div className="flex items-center gap-2">
      {checked ? (
        <Check size={16} className="text-success-600" />
      ) : (
        <X size={16} className="text-gray-300" />
      )}
      <span className={`text-sm ${checked ? 'text-gray-700 font-medium' : 'text-gray-400'}`}>
        {label}
      </span>
    </div>
  );

  return (
    <div className={className}>
      {/* Strength Bar */}
      <div className="mb-2">
        <div className="flex items-center justify-between mb-1">
          <span className="text-xs font-medium text-gray-600">Password Strength</span>
          <span className={`text-xs font-bold ${getStrengthLabelColor(strength)}`}>
            {getStrengthLabel(strength)}
          </span>
        </div>

        <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
          <div
            className={`h-full transition-all duration-300 ${getStrengthColor(strength)}`}
            style={{
              width:
                strength === 'weak' ? '33%' : strength === 'medium' ? '66%' : '100%',
            }}
          />
        </div>
      </div>

      {/* Details */}
      {showDetails && (
        <div className="mt-3 space-y-1.5 p-3 bg-gray-50 rounded-lg">
          <p className="text-xs font-semibold text-gray-700 mb-2">Password Requirements:</p>

          <CheckItem label="At least 8 characters" checked={checks.minLength} />
          <CheckItem label="Uppercase letter (A-Z)" checked={checks.hasUppercase} />
          <CheckItem label="Lowercase letter (a-z)" checked={checks.hasLowercase} />
          <CheckItem label="Number (0-9)" checked={checks.hasNumber} />
          <CheckItem label="Special character (!@#$%^&*)" checked={checks.hasSpecialChar} />
        </div>
      )}

      {/* Tips */}
      {password.length > 0 && !validation.isValid && (
        <p className="text-xs text-error-600 mt-2">
          ΓÜá∩╕Å Your password is too weak. Please add uppercase, lowercase, and a number.
        </p>
      )}

      {password.length > 0 && validation.isValid && strength === 'weak' && (
        <p className="text-xs text-warning-600 mt-2">
          ≡ƒÆí Consider adding special characters for a stronger password.
        </p>
      )}

      {password.length > 0 && strength === 'strong' && (
        <p className="text-xs text-success-600 mt-2">
          Γ£ô Excellent password strength!
        </p>
      )}
    </div>
  );
};

